mapper.select:
select sale.id as rowId , sale.name as name,sale.sub_flag as subFlag,sale.start_date as startDate, cslt.name as lecTypeName,csll.name as lecLevelName, sdept.name as deptName,ddept.name as divisionName, sale.lec_address as lecAddress,sale.intro as intro,sale.listeners_num as listenersNum, luser.name as lecturerName, csru.name as lecturerUnitName,sale.lecturer_duty as lecturerDuty, ccsti.name as lecturerTitleName,sale.lecturer_info as lecturerInfo, fdiscipline.name as relatedSubjectName,sale.compere as compere,sale.commend as commend, luser1.name as creatorName,luser2.name as subUserName,sale.create_time,sale.sub_date from srm_ac_lecture sale left join ct_srm_lecture_level csll on csll.code=sale.lec_level left join ct_srm_lecture_type cslt on cslt.code=sale.lec_type left join ct_srm_dept sdept on sdept.id=sale.dept_id left join ct_srm_dept ddept on ddept.id=sale.division left join ct_srm_user luser on luser.id=sale.lecturer left join ct_srm_user luser1 on luser1.id=sale.creator_id left join ct_srm_user luser2 on luser2.id=sale.sub_user_id left join ct_srm_rely_unit csru on csru.code=sale.lecturer_unit left join ct_srm_title_info ccsti on ccsti.code=sale.lecturer_title left join ct_srm_discipline fdiscipline on fdiscipline.code=sale.related_subject
where (sale.sub_user_id=#{acLectureDto.userId} or sale.creator_id=#{acLectureDto.userId} or sale.lecturer=#{acLectureDto.userId})
and sale.sub_flag =#{acLectureDto.subFlag}
and sale.name LIKE CONCAT('%', #{acLectureDto.name}, '%')
and sale.sub_date >= #{acLectureDto.startDate}
and sale.sub_date <= #{acLectureDto.endDate}
and sale.dept_id =#{acLectureDto.deptId}
and sale.lec_type =#{acLectureDto.lecType}
and sale.lec_level =#{acLectureDto.lecLevel}
and sale.lec_address LIKE CONCAT('%', #{acLectureDto.lecAddress}, '%')
and sale.listeners_num =#{acLectureDto.listenersNum}
order by sale.id desc

select sale.id as rowId , sale.name as name,sale.sub_flag as subFlag,sale.start_date as startDate, cslt.name as lecTypeName,csll.name as lecLevelName, sdept.name as deptIdName,ddept.name as divisionName, sale.lec_address as lecAddress,sale.intro as intro,sale.listeners_num as listenersNum, luser.name as lecturerName,sale.sub_date as subDate,auser.name as subUserName, csru.name as lecturerUnitName,sale.lecturer_duty as lecturerDuty, ccsti.name as lecturerTitleName,sale.lecturer_info as lecturerInfo, fdiscipline.name as relatedSubjectName,sale.compere as compere,sale.commend as commend from srm_ac_lecture sale left join ct_srm_lecture_level csll on csll.code=sale.lec_level left join ct_srm_lecture_type cslt on cslt.code=sale.lec_type left join ct_srm_dept sdept on sdept.id=sale.dept_id left join ct_srm_dept ddept on ddept.id=sale.division left join ct_srm_user luser on luser.id=sale.lecturer left join ct_srm_user auser on auser.id=sale.sub_user_id left join ct_srm_rely_unit csru on csru.code=sale.lecturer_unit left join ct_srm_title_info ccsti on ccsti.code=sale.lecturer_title left join ct_srm_discipline fdiscipline on fdiscipline.code=sale.related_subject left join cf_srm_eaf_rec eafrec on eafrec.sys_no="P041" and eafrec.check_rec_id=sale.id where eafrec.step_no>1
and sale.name LIKE CONCAT('%', #{acLectureDto.name}, '%')
and sale.sub_date >= #{acLectureDto.startDate}
and sale.sub_date <= #{acLectureDto.endDate}
and sale.dept_id =#{acLectureDto.deptId}
and sale.lec_type =#{acLectureDto.lecType}
and sale.lec_level =#{acLectureDto.lecLevel}
and sale.lec_address LIKE CONCAT('%', #{acLectureDto.lecAddress}, '%')
and sale.listeners_num =#{acLectureDto.listenersNum}
and ( (sale.sub_flag=1 and eafrec.is_current_step=1 and eafrec.checker_string LIKE CONCAT('%|', #{acLectureDto.userId}, '|%')) or (eafrec.step_no = (select max(step_no) from cf_srm_eaf_rec seafrec where seafrec.sys_no="P041" and seafrec.check_rec_id=sale.id) and eafrec.checker_string LIKE CONCAT('%|', #{acLectureDto.userId}, '|%') and eafrec.check_datetime is not null) or (sale.sub_flag=0 and eafrec.is_current_step=1 and eafrec.check_result=3 and eafrec.checker_string LIKE CONCAT('%|', #{acLectureDto.userId}, '|%')) )
and sale.sub_flag=1 and eafrec.is_current_step=1 and eafrec.checker_string LIKE CONCAT('%|', #{acLectureDto.userId}, '|%')
and sale.sub_flag=1 and eafrec.check_result="2" and eafrec.checker_string LIKE CONCAT('%|', #{acLectureDto.userId}, '|%')
and sale.sub_flag=0 and eafrec.check_result="3" and eafrec.checker_string LIKE CONCAT('%|', #{acLectureDto.userId}, '|%')
